    for (int i = 0; i < cycle.size(); i++) {
        for (int j = i + 1; j < cycle.size(); j++) {
            int dist = min(j - i, (int)cycle.size() - (j - i));
            res = max(res, dist + max_depth[cycle[i]] + max_depth[cycle[j]]);
        }
    }

    return res;
}
```

**解題技巧**：

1. **先找環**：使用拓撲排序或 DFS 找出環
2. **標記環**：用布爾陣列標記哪些節點在環上
3. **分情況討論**：環上節點和環外節點分別處理
4. **斷環成樹**：某些 DP 問題需要斷開環變成樹
5. **雙向考慮**：環上距離需要考慮順時針和逆時針兩個方向

**時間複雜度**：
- 找環：$O(n)$（拓撲排序或 DFS）
- 樹形 DP：$O(n)$
- 總體：$O(n)$

**識別基環樹的特徵**：
- 題目明確說「n 個節點，n 條邊」
- 每個節點恰好有一條出邊（有向圖）
- 問題涉及環的性質或需要斷環處理

**Dijkstra 演算法**：
- 適用於非負權圖的單源最短路
- 使用優先佇列 (heap) 優化，時間複雜度分析：

**時間複雜度詳解**：

1. **$O(E \log E)$**：不使用 `visited` 陣列標記的實現
   - 每條邊可能導致一次入隊操作：$O(E)$ 次
   - 每次入隊需要堆操作：$O(\log E)$
   - 總複雜度：$O(E \log E)$
   - 堆中最多有 E 個元素（每條邊可能產生一個入隊）

2. **$O(E \log V)$**：使用 `visited` 陣列或優化的實現
   - 每個節點最多出隊一次：$O(V)$ 次
   - 總共處理所有邊：$O(E)$ 次
   - 每次入隊的堆操作：$O(\log V)$（因為堆中最多 V 個節點）
   - 總複雜度：$O(E \log V)$

**兩種複雜度的對比**：

由於 $E \leq V^2$（完全圖），所以 $\log E \leq 2\log V$，因此：
$$O(E \log E) = O(E \log V)$$

實際上兩種分析方式得到的複雜度是等價的，只是分析角度不同。

**何時用哪個表示？**

- **稀疏圖**（$E \approx V$）：兩者相同，都是 $O(V \log V)$
- **稠密圖**（$E \approx V^2$）：
  - $O(E \log E) \approx O(V^2 \log V)$
  - $O(E \log V) \approx O(V^2 \log V)$
  - 使用 $O(V^2)$ 的暴力實現可能更快

**優化技巧**：

- 使用 `if (d > dist[u]) continue;` 跳過過時的堆元素
- 稠密圖考慮使用鄰接矩陣 + $O(V^2)$ 實現
- C++ 使用 `priority_queue` 或斐波那契堆（理論 $O(E + V \log V)$）

```cpp
// Dijkstra 演算法：貪心鬆弛，適用於非負權圖
vector<int> dist(n, INT_MAX);
dist[start] = 0;
priority_queue<pair<int, int>, vector<pair<int, int>>, greater<>> pq;
pq.push({0, start});
while (!pq.empty()) {
    auto [d, u] = pq.top();
    pq.pop();
    if (d > dist[u]) { // 已有更短路徑，跳過
        continue;
    }
    for (auto& [v, w] : adj[u]) {
        if (dist[u] + w < dist[v]) { // 鬆弛操作
            dist[v] = dist[u] + w;
            pq.push({dist[v], v});
        }
    }
}
```

**SPFA（Shortest Path Faster Algorithm）**：Bellman-Ford 的佇列優化版本，可處理負權邊，並可判斷負環。

- 平均時間複雜度 $O(kE)$，k 為常數（通常很小），最差退化為 $O(VE)$
- 若某節點入佇列次數 $\geq V$，則存在負環

**C++ 模板（SPFA 最短路）**：

```cpp
// adj[u] = {{v, w}, ...}
vector<vector<pair<int, int>>> adj(n);
vector<long long> dist(n, LLONG_MAX);
vector<bool> in_queue(n, false);
vector<int> cnt(n, 0); // 入佇列次數，用於判負環

bool spfa(int src) {
    dist[src] = 0;
    queue<int> q;
    q.push(src);
    in_queue[src] = true;
    while (!q.empty()) {
        int u = q.front();
        q.pop();
        in_queue[u] = false;
        for (auto& [v, w] : adj[u]) {
            if (dist[u] + w < dist[v]) {
                dist[v] = dist[u] + w;
                if (!in_queue[v]) {
                    q.push(v);
                    in_queue[v] = true;
                    if (++cnt[v] >= n) {
                        return false; // 存在負環
                    }
                }
            }
        }
    }
    return true; // 無負環
}
```

**差分約束**：將不等式 $x[j] - x[i] \leq w$ 轉化為圖的邊 $i \to j$，權值為 $w$，用 SPFA 求解。若有負環則無解。

**Floyd-Warshall 演算法**：
- 適用於動態規劃求所有點對間的最短路
- 時間複雜度 $O(V³)$，適用於 V 較小 (如 V <= 300) 的圖

```cpp
// Floyd 演算法：三層迴圈求所有點對最短路
for (int k = 0; k < n; ++k) { // 列舉中繼點 k
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            if (dist[i][k] != inf && dist[k][j] != inf) {
                dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j]); // 嘗試經過 k 中轉
            }
        }
    }
}
```

涉及到 Kruskal 演算法和 Prim 演算法。前者一般用於稀疏圖，後者一般用於稠密圖。

> 注：如果要求最大生成樹，把邊權從大到小排序。

Kruskal 演算法模板（用到了並查集，完整模板見 [資料結構題單](https://leetcode.cn/circle/discuss/mOr1u6/)）：

```cpp
// Kruskal 演算法用的並查集
struct UnionFindMst {
    vector<int> fa; // fa[x] = x 的父節點
    int cc;         // 連通塊個數
    explicit UnionFindMst(int n) : fa(n), cc(n) {
        iota(fa.begin(), fa.end(), 0); // 初始每個節點自成一個集合
    }

    // 路徑壓縮查詢根節點
    int find(int x) {
        return fa[x] == x ? x : fa[x] = find(fa[x]);
    }

    // 合併 x, y 所在集合，成功回傳 true
    bool merge(int x, int y) {
        x = find(x);
        y = find(y);
        if (x == y) {
            return false; // 已在同一集合
        }
        fa[x] = y;
        cc -= 1; // 連通塊個數減一
        return true;
    }
};

// 計算圖的最小生成樹的邊權之和；如果圖不連通，返回 kInf
long long mstKruskal(int n, vector<array<int, 3>> edges) {
    const long long kInf = 1LL << 60;
    // 按邊權從小到大排序
    sort(edges.begin(), edges.end(), [](auto& a, auto& b) { return a[2] < b[2]; });
    UnionFindMst uf(n);
    long long sum_wt = 0;
    for (auto& e : edges) {
        int x = e[0], y = e[1], wt = e[2];
        if (uf.merge(x, y)) { // 若 x, y 不在同一集合，合併並計入邊權 {
            sum_wt += wt;
        }
        }
    }

    if (uf.cc > 1) {
        return kInf; // 圖不連通
    }
    return sum_wt;
}
```

Prim 演算法模板（最小堆）：

```cpp
// Prim 演算法：從起點出發，每次選最小權邊擴展生成樹
long long mstPrim(int n, const vector<vector<pair<int, int>>>& adj) {
    const long long kInf = 1LL << 60;
    vector<long long> min_edge(n, kInf); // min_edge[v] = 連線 v 到生成樹的最小邊權
    vector<bool> in_mst(n, false);
    priority_queue<pair<long long, int>, vector<pair<long long, int>>, greater<>> pq;
    min_edge[0] = 0;
    pq.push({0, 0}); // 從節點 0 開始
    long long total_weight = 0;
    int picked = 0;
    while (!pq.empty()) {
        auto [w, u] = pq.top();
        pq.pop();
        if (in_mst[u]) { // 已加入生成樹，跳過 {
            continue;
        }
        }
        in_mst[u] = true;
        total_weight += w;
        picked++;
        for (auto& [v, weight] : adj[u]) {
            if (!in_mst[v] && weight < min_edge[v]) { // 發現更小的連線邊 {
                min_edge[v] = weight;
            }
                pq.push({weight, v});
            }
        }
    }
    if (picked != n) {
        return kInf; // 圖不連通
    }
    return total_weight;
}
```

**Kruskal 演算法**：
- 貪心策略：按邊權從小到大排序，使用並查集(DSU) 維護連通性
- 時間複雜度 $O(E \log E)$

**Prim 演算法**：
- 貪心策略：從任意起點出發，每次選擇連線當前生成樹的最小權邊
- 需使用最小堆維護當前可擴展邊權最小值
- 時間複雜度 $O(E \log V)$

涉及到 Tarjan 演算法。

**強連通分量 (SCC) 模板 (Tarjan 演算法)**：

```cpp
// Tarjan 演算法：求強連通分量（SCC）
int dfn[kMaxN], low[kMaxN], timestamp;
stack<int> st;
bool in_stack[kMaxN];
int scc[kMaxN], scc_cnt;

void tarjan(int u) {
    dfn[u] = low[u] = ++timestamp; // 記錄 DFS 序
    st.push(u);
    in_stack[u] = true;
    for (int v : adj[u]) {
        if (!dfn[v]) {
            tarjan(v);
            low[u] = min(low[u], low[v]); // 用子節點更新可達最早時間
        } else if (in_stack[v]) {
            low[u] = min(low[u], dfn[v]); // 用回邊更新
        }
    }

    if (dfn[u] == low[u]) { // u 是 SCC 的根
        scc_cnt++;
        int v;
        do {
            v = st.top();
            st.pop();
            in_stack[v] = false;
            scc[v] = scc_cnt;
        } while (u != v);
    }
}
```

**雙連通分量(BCC) / 割邊(Bridge) 模板**：
```cpp
// Tarjan 求橋（割邊）與割點
void tarjan(int u, int p) {
    dfn[u] = low[u] = ++timestamp;
    for (int v : adj[u]) {
        if (v == p) {
            continue;
        }
        if (!dfn[v]) {
            tarjan(v, u);
            low[u] = min(low[u], low[v]);
            if (low[v] > dfn[u]) {
                // (u, v) 是一條割邊
            }
        } else {
            low[u] = min(low[u], dfn[v]);
        }
    }
}
```

**關鍵概念說明**：
- **割邊 (Bridge)**：刪除後會使圖的連通分量數增加的邊，也叫「橋」
- **割點 (Articulation Point)**：刪除後會使圖的連通分量數增加的點
- **雙連通分量 (BCC)**：沒有割點的極大子圖，分為點雙連通和邊雙連通

**判斷條件**：
- 邊 $(u, v)$ 是割邊 $\iff$ `low[v] > dfn[u]`（$v$ 無法繞回 $u$ 或其祖先）
- 點 $u$ 是割點 $\iff$ 存在子節點 $v$ 使得 `low[v] >= dfn[u]`
- 對於根節點，需要至少有兩個子樹纔是割點

**時間複雜度**：$O(V + E)$，每條邊和每個點只被訪問一次

模板（交替染色法）：

```cpp
// 返回圖的二染色；如果不是二分圖則返回空陣列
vector<int> colorBipartite(int n, const vector<vector<int>>& edges) {
    vector<vector<int>> g(n);
    for (auto& e : edges) {
        int x = e[0], y = e[1];
        g[x].push_back(y);
        g[y].push_back(x);
    }

    vector<int> colors(n, 0);
    function<bool(int, int)> dfs = [&](int x, int c) {
        colors[x] = c; // 節點 x 染成顏色 c
        for (int y : g[x]) {
            if (colors[y] == c) {
                return false; // 鄰居同色，不是二分圖
            }
            if (colors[y] == 0 && !dfs(y, 3 - c)) {
                return false; // 1 和 2 交替染色
            }
        }
        return true;
    };

    for (int i = 0; i < n; i++) {
        if (colors[i] == 0 && !dfs(i, 1)) {
            return {}; // i 所在連通塊不是二分圖
        }
    }
    return colors;
}
```

**二分圖判定**：
- 圖是二分圖的充分必要條件是圖中不存在奇環
- 使用 DFS 或 BFS 進行 0/1 染色，若鄰居顏色相同則非二分圖

由於有其他做法（比如狀壓 DP），難度分僅供參考。

```cpp
// 最大流：Dinic 演算法模板
struct Dinic {
    struct Edge {
        int to, rev;
        int cap;
    };
    vector<vector<Edge>> graph;
    vector<int> level, iter;
    Dinic(int n) : graph(n), level(n), iter(n) {
    }
    void addEdge(int from, int to, int cap) {
        graph[from].push_back({to, (int)graph[to].size(), cap});
        graph[to].push_back({from, (int)graph[from].size() - 1, 0});
    }
    bool bfs(int s, int t) {
        fill(level.begin(), level.end(), -1);
        queue<int> q;
        level[s] = 0;
        q.push(s);
        while (!q.empty()) {
            int v = q.front();
            q.pop();
            for (auto& e : graph[v])
                if (e.cap > 0 && level[e.to] < 0) {
                    level[e.to] = level[v] + 1;
                    q.push(e.to);
                }
        }
        return level[t] >= 0;
    }
    int dfs(int v, int t, int f) {
        if (v == t) {
            return f;
        }
        for (int& i = iter[v]; i < (int)graph[v].size(); i++) {
            Edge& e = graph[v][i];
            if (e.cap > 0 && level[v] < level[e.to]) {
                int d = dfs(e.to, t, min(f, e.cap));
                if (d > 0) {
                    e.cap -= d;
                    graph[e.to][e.rev].cap += d;
                    return d;
                }
            }
        }
        return 0;
    }
    int maxflow(int s, int t) {
        int flow = 0;
        while (bfs(s, t)) {
            fill(iter.begin(), iter.end(), 0);
            int d;
            while ((d = dfs(s, t, INT_MAX)) > 0) {
                flow += d;
            }
        }
        return flow;
    }
};
```

